#include <iostream>
#include <iomanip>
using namespace std;

int main() {
    int N;
    cin >> N;

    int arr[9][9]; // N < 10, so max 9x9

    int num = 1;
    for (int i = 0; i < N; i++) {
        if (i % 2 == 0) {
            // odd row (0-indexed even): right to left
            for (int j = N - 1; j >= 0; j--) {
                arr[i][j] = num++;
            }
        } else {
            // even row (0-indexed odd): left to right
            for (int j = 0; j < N; j++) {
                arr[i][j] = num++;
            }
        }
    }

    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            cout << setw(3) << arr[i][j];
        }
        cout << endl;
    }

    return 0;
}
